import { forwardRef } from 'react';

export type IndicatorVariant = 'unsaved' | 'new' | 'unread';
export type IndicatorSize = 'sm' | 'lg';

export interface ArvoIndicatorProps {
  variant: IndicatorVariant;
  size?: IndicatorSize;
  className?: string;
}

const ArvoIndicator = forwardRef<HTMLSpanElement, ArvoIndicatorProps>(
  function ArvoIndicator({ variant, size = 'lg', className }, ref) {
    const classes = [
      'arvo-indicator',
      `arvo-indicator--${variant}`,
      `arvo-indicator--${size}`,
      className ?? '',
    ]
      .filter(Boolean)
      .join(' ');

    return (
      <span ref={ref} className={classes} aria-hidden="true" />
    );
  }
);

export default ArvoIndicator;
